const searchInput=document.getElementById("search"),searchResults=document.getElementById("search-result");fetch("/index.json").then(e=>e.json()).then(e=>{const t=lunr(function(){this.ref("url"),this.field("title"),this.field("content"),e.forEach(e=>{this.add(e)})});searchInput.addEventListener("input",function(){const n=searchInput.value,s=t.search(n);searchResults.innerHTML="",s.forEach(t=>{const n=e.find(e=>e.url===t.ref),s=document.createElement("li");s.innerHTML=`<a href="${n.url}">${n.title}</a>`,searchResults.appendChild(s)})})}).catch(e=>console.error(e))